  1	import * as React from 'react';
  2	import {
  3	  deviceTypeDropdownItems,
  4	  diskModeDropdownItems,
  5	  diskSizeUnitOptions,
  6	  diskTypeDropdownItems,
  7	  fsTypeDropdownItems,
  8	} from '@odf/core/constants';
  9	import { DiskType, NodeData } from '@odf/core/types';
 10	import { STORAGE_SIZE_UNIT_NAME_MAP } from '@odf/shared/constants';
 11	import { MultiSelectDropdown } from '@odf/shared/dropdown/multiselectdropdown';
 12	import { SingleSelectDropdown } from '@odf/shared/dropdown/singleselectdropdown';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { NodeKind } from '@openshift-console/dynamic-plugin-sdk';
 15	import * as _ from 'lodash-es';
 16	import { TFunction } from 'react-i18next';
 17	import {
 18	  Alert,
 19	  AlertVariant,
 20	  FormGroup,
 21	  TextInput,
 22	  Radio,
 23	  ExpandableSection,
 24	  TextInputTypes,
 25	  Text,
 26	  TextVariants,
 27	  Tooltip,
 28	  SelectOption,
 29	} from '@patternfly/react-core';
 30	import { SelectNodesTable } from '../../create-storage-system/select-nodes-table/select-nodes-table';
 31	import { createWizardNodeState } from '../../utils';
 32	import { Action, State } from './state';
 33	import '../../create-storage-system/create-storage-system-steps/create-local-volume-set-step/body.scss';
 34	
 35	const fsTypeDropdownOptions: JSX.Element[] = _.map(
 36	  fsTypeDropdownItems,
 37	  (v, _unused) => (
 38	    <SelectOption key={v} value={v}>
 39	      {v}
 40	    </SelectOption>
 41	  )
 42	);
 43	
 44	const diskModeDropdownOptions: JSX.Element[] = _.map(
 45	  diskModeDropdownItems,
 46	  (v, _unused) => (
 47	    <SelectOption key={v} value={v}>
 48	      {v}
 49	    </SelectOption>
 50	  )
 51	);
 52	
 53	const diskSizeUnitDropdownOptions: JSX.Element[] = _.map(
 54	  diskSizeUnitOptions,
 55	  (v, _unused) => (
 56	    <SelectOption key={v} value={v}>
 57	      {v}
 58	    </SelectOption>
 59	  )
 60	);
 61	
 62	const deviceTypeDropdownOptions: (t: TFunction) => JSX.Element[] = (t) =>
 63	  _.map(deviceTypeDropdownItems, (v) => (
 64	    <SelectOption
 65	      key={v}
 66	      value={v}
 67	      {...(v === deviceTypeDropdownItems.MPATH
 68	        ? {
 69	            description: t(
 70	              'This selection is exclusive and cannot be used with other device types.'
 71	            ),
 72	          }
 73	        : {})}
 74	    >
 75	      {v}
 76	    </SelectOption>
 77	  ));
 78	
 79	const diskTypeDropdownOptions: (t: TFunction) => JSX.Element[] = (t) =>
 80	  _.map(diskTypeDropdownItems(t), (v, _unused) => (
 81	    <SelectOption key={v} value={v}>
 82	      {v}
 83	    </SelectOption>
 84	  ));
 85	
 86	export enum FilterDiskBy {
 87	  ALL_NODES = 'all-nodes',
 88	  SELECTED_NODES = 'selected-nodes',
 89	}
 90	
 91	const AllNodesLabel: React.FC<{ count: number }> = ({ count }) => {
 92	  const { t } = useCustomTranslation();
 93	  return (
 94	    <>
 95	      {t('Disks on all nodes')}
 96	      {' ('}
 97	      {t('{{nodes, number}} node', {
 98	        nodes: count,
 99	        count,
100	      })}
101	      {')'}
102	    </>
103	  );
104	};
105	
106	const getDiskTypeValidationError = (state: State, t: TFunction) => {
107	  let validationError: {
108	    title: string;
109	    variant?: AlertVariant;
110	  };
111	
112	  if (state.diskType === DiskType.All)
113	    validationError = {
114	      title: t(
115	        'All disk type may include HDD disks. Data Foundation does not support HDD disks as local devices. Select SSD if you plan to use Data Foundation.'
116	      ),
117	      variant: AlertVariant.info,
118	    };
119	  if (state.diskType === DiskType.HDD)
120	    validationError = {
121	      title: t(
122	        'Data Foundation does not support HDD disks as local devices. Select SSD if you plan to use Data Foundation.'
123	      ),
124	      variant: AlertVariant.info,
125	    };
126	
127	  return validationError;
128	};
129	
130	export const LocalVolumeSetBody: React.FC<LocalVolumeSetBodyProps> = ({
131	  dispatch,
132	  state,
133	}) => {
134	  const { t } = useCustomTranslation();
135	
136	  const INTEGER_MAX_REGEX = /^\+?([1-9]\d*)$/;
137	  const INTEGER_MIN_REGEX = /^\+?([0-9]\d*)$/;
138	  const [activeMinDiskSize, setMinActiveState] = React.useState(false);
139	  const [activeMaxDiskSize, setMaxActiveState] = React.useState(false);
140	  const validMinDiskSize = INTEGER_MIN_REGEX.test(state.minDiskSize || '1');
141	  const validMaxDiskSize = INTEGER_MAX_REGEX.test(state.maxDiskSize || '1');
142	  const validMaxDiskLimit = INTEGER_MAX_REGEX.test(state.maxDiskLimit || '1');
143	
144	  const invalidMinGreaterThanMax =
145	    state.minDiskSize !== '' &&
146	    state.maxDiskSize !== '' &&
147	    Number(state.minDiskSize) > Number(state.maxDiskSize);
148	
149	  const toggleShowNodesList = () =>
150	    dispatch({ type: 'setLvsIsSelectNodes', value: !state.lvsIsSelectNodes });
151	
152	  const diskSizeHelpText = t('Please enter a positive Integer');
153	
154	  const onRowSelected = React.useCallback(
155	    (selectedNodes: NodeData[]) => {
156	      dispatch({
157	        type: 'setLvsSelectNodes',
158	        value: selectedNodes as unknown as NodeKind[],
159	      });
160	    },
161	    [dispatch]
162	  );
163	
164	  const diskTypeValidationError = getDiskTypeValidationError(state, t);
165	
166	  return (
167	    <>
168	      <FormGroup
169	        label={t('LocalVolumeSet name')}
170	        isRequired
171	        fieldId="create-lvs-volume-set-name"
172	      >
173	        <TextInput
174	          type={TextInputTypes.text}
175	          id="create-lvs-volume-set-name"
176	          value={state.volumeSetName}
177	          onChange={(_event, name: string) =>
178	            dispatch({ type: 'setVolumeSetName', name })
179	          }
180	          isRequired
181	        />
182	      </FormGroup>
183	      <FormGroup
184	        label={t('StorageClass Name')}
185	        fieldId="create-lvs-storage-class-name"
186	      >
187	        <TextInput
188	          type={TextInputTypes.text}
189	          id="create-lvs-storage-class-name"
190	          value={state.storageClassName}
191	          placeholder={state.volumeSetName}
192	          onChange={(_event, name: string) =>
193	            dispatch({ type: 'setStorageClassName', name })
194	          }
195	        />
196	      </FormGroup>
197	      <Text
198	        component={TextVariants.h3}
199	        className="odf-create-lvs__filter-volumes-text--margin"
200	      >
201	        {t('Filter disks by')}
202	      </Text>
203	      <FormGroup fieldId="create-lvs-radio-group-node-selector">
204	        <div id="create-lvs-radio-group-node-selector">
205	          <Radio
206	            label={<AllNodesLabel count={state.lvsAllNodes.length} />}
207	            description={t(
208	              'Uses the available disks that match the selected filters on all nodes.'
209	            )}
210	            name="nodes-selection"
211	            id="create-lvs-radio-all-nodes"
212	            className="lso-create-lvs__all-nodes-radio--padding"
213	            value="allNodes"
214	            onChange={toggleShowNodesList}
215	            checked={!state.lvsIsSelectNodes}
216	          />
217	          <Radio
218	            label={t('Disks on selected nodes')}
219	            name="nodes-selection"
220	            id="create-lvs-radio-select-nodes"
221	            value="selectedNodes"
222	            onChange={toggleShowNodesList}
223	            description={t(
224	              'Uses the available disks that match the selected filters only on selected nodes.'
225	            )}
226	            checked={state.lvsIsSelectNodes}
227	          />
228	        </div>
229	      </FormGroup>
230	      {state.lvsIsSelectNodes && (
231	        <SelectNodesTable
232	          nodes={createWizardNodeState(
233	            state.lvsAllNodes as unknown as NodeData[]
234	          )}
235	          onRowSelected={onRowSelected}
236	          systemNamespace={''}
237	        />
238	      )}
239	      <FormGroup label={t('Disk type')} fieldId="create-lvs-disk-type-dropdown">
240	        <SingleSelectDropdown
241	          id="create-lvs-disk-type-dropdown"
242	          className="dropdown--full-width"
243	          selectOptions={diskTypeDropdownOptions(t)}
244	          selectedKey={diskTypeDropdownItems(t)[state.diskType]}
245	          onChange={(type: DiskType) =>
246	            dispatch({ type: 'setDiskType', value: type })
247	          }
248	          valueLabelMap={diskTypeDropdownItems(t)}
249	        />
250	        {!!diskTypeValidationError && (
251	          <Alert
252	            className="pf-v6-u-mt-md"
253	            variant={diskTypeValidationError.variant || AlertVariant.danger}
254	            title={diskTypeValidationError.title}
255	            isInline
256	          />
257	        )}
258	      </FormGroup>
259	      <ExpandableSection
260	        toggleText={t('Advanced')}
261	        data-test-id="create-lvs-form-advanced"
262	      >
263	        <FormGroup
264	          label={t('Volume mode')}
265	          fieldId="create-odf-disk-mode-dropdown"
266	          className="odf-create-lvs__disk-mode-dropdown--margin"
267	        >
268	          <SingleSelectDropdown
269	            id="create-odf-disk-mode-dropdown"
270	            className="dropdown--full-width"
271	            selectOptions={diskModeDropdownOptions}
272	            selectedKey={state.diskMode}
273	            onChange={(mode: string) => {
274	              dispatch({
275	                type: 'setDiskMode',
276	                value: diskModeDropdownItems[mode],
277	              });
278	            }}
279	            valueLabelMap={diskModeDropdownItems}
280	          />
281	        </FormGroup>
282	        <FormGroup
283	          label={t('Device type')}
284	          fieldId="create-odf-device-type-dropdown"
285	          className="odf-create-lvs__device-type-dropdown--margin"
286	        >
287	          <MultiSelectDropdown
288	            id="create-odf-device-type-dropdown"
289	            selections={state.deviceType}
290	            selectOptions={deviceTypeDropdownOptions(t)}
291	            placeholderText={t('Select disk types')}
292	            onChange={(selectedValues: string[]) => {
293	              dispatch({ type: 'setDeviceType', value: selectedValues });
294	            }}
295	          />
296	        </FormGroup>
297	        {state.diskMode === diskModeDropdownItems.FILESYSTEM && (
298	          <FormGroup
299	            label={t('File System Type')}
300	            fieldId="create-lso-fs-type-dropdown"
301	            className="lso-create-lvs__fs-type-dropdown--margin"
302	          >
303	            <SingleSelectDropdown
304	              id="create-lso-fs-type-dropdown"
305	              className="dropdown--full-width"
306	              selectOptions={fsTypeDropdownOptions}
307	              selectedKey={state.fsType}
308	              onChange={(mode: string) => {
309	                dispatch({
310	                  type: 'setFsType',
311	                  value: fsTypeDropdownItems[mode],
312	                });
313	              }}
314	              valueLabelMap={fsTypeDropdownItems}
315	            />
316	          </FormGroup>
317	        )}
318	        <FormGroup
319	          label={t('Disk size')}
320	          fieldId="create-lvs-disk-size"
321	          className="odf-create-lvs__disk-size-form-group--margin"
322	        >
323	          <div
324	            id="create-lvs-disk-size"
325	            className="odf-create-lvs__disk-size-form-group-div"
326	          >
327	            <FormGroup
328	              label={t('Minimum')}
329	              fieldId="create-lvs-min-disk-size"
330	              className="odf-create-lvs__disk-size-form-group-max-min-input"
331	            >
332	              <Tooltip
333	                content={
334	                  !validMinDiskSize
335	                    ? diskSizeHelpText
336	                    : t(
337	                        'Please enter a value less than or equal to max disk size'
338	                      )
339	                }
340	                isVisible={
341	                  !validMinDiskSize ||
342	                  (invalidMinGreaterThanMax && activeMinDiskSize)
343	                }
344	                trigger="manual"
345	              >
346	                <TextInput
347	                  type={TextInputTypes.text}
348	                  id="create-lvs-min-disk-size"
349	                  value={state.minDiskSize}
350	                  validated={
351	                    !validMinDiskSize ||
352	                    (invalidMinGreaterThanMax && activeMinDiskSize)
353	                      ? 'error'
354	                      : 'default'
355	                  }
356	                  className="odf-create-lvs__disk-input"
357	                  onFocus={() => setMinActiveState(true)}
358	                  onBlur={() => setMinActiveState(false)}
359	                  onChange={(_event, size: string) => {
360	                    dispatch({ type: 'setMinDiskSize', value: size });
361	                  }}
362	                />
363	              </Tooltip>
364	            </FormGroup>
365	            <div>-</div>
366	            <FormGroup
367	              label={t('Maximum')}
368	              fieldId="create-lvs-max-disk-size"
369	              className="odf-create-lvs__disk-size-form-group-max-min-input"
370	            >
371	              <Tooltip
372	                content={
373	                  !validMaxDiskSize
374	                    ? diskSizeHelpText
375	                    : t(
376	                        'Please enter a value greater than or equal to min disk size'
377	                      )
378	                }
379	                isVisible={
380	                  !validMaxDiskSize ||
381	                  (invalidMinGreaterThanMax && activeMaxDiskSize)
382	                }
383	                trigger="manual"
384	              >
385	                <TextInput
386	                  type={TextInputTypes.text}
387	                  id="create-lvs-max-disk-size"
388	                  value={state.maxDiskSize}
389	                  validated={
390	                    !validMaxDiskSize ||
391	                    (invalidMinGreaterThanMax && activeMaxDiskSize)
392	                      ? 'error'
393	                      : 'default'
394	                  }
395	                  className="odf-create-lvs__disk-input"
396	                  onFocus={() => setMaxActiveState(true)}
397	                  onBlur={() => setMaxActiveState(false)}
398	                  onChange={(_event, value) =>
399	                    dispatch({ type: 'setMaxDiskSize', value })
400	                  }
401	                />
402	              </Tooltip>
403	            </FormGroup>
404	            <FormGroup
405	              label={t('Units')}
406	              fieldId="create-lvs-disk-size-unit-dropdown"
407	              className="odf-create-lvs__disk-size-form-group-max-min-input"
408	            >
409	              <SingleSelectDropdown
410	                id="create-lvs-disk-size-unit-dropdown"
411	                selectOptions={diskSizeUnitDropdownOptions}
412	                selectedKey={STORAGE_SIZE_UNIT_NAME_MAP[state.diskSizeUnit]}
413	                onChange={(unit: string) => {
414	                  dispatch({ type: 'setDiskSizeUnit', value: unit });
415	                }}
416	                valueLabelMap={diskSizeUnitOptions}
417	              />
418	            </FormGroup>
419	          </div>
420	        </FormGroup>
421	        <FormGroup
422	          label={t('Maximum disks limit')}
423	          fieldId="create-lvs-max-disk-limit"
424	        >
425	          <p className="help-block odf-create-lvs__max-disk-limit-help-text--margin">
426	            {t(
427	              'Disks limit will set the maximum number of PVs to create on a node. If the field is empty we will create PVs for all available disks on the matching nodes.'
428	            )}
429	          </p>
430	          <Tooltip
431	            content={diskSizeHelpText}
432	            isVisible={!validMaxDiskLimit}
433	            trigger="manual"
434	          >
435	            <TextInput
436	              type={TextInputTypes.text}
437	              id="create-lvs-max-disk-limit"
438	              value={state.maxDiskLimit}
439	              validated={validMaxDiskLimit ? 'default' : 'error'}
440	              className="odf-create-lvs__disk-input"
441	              onChange={(_event, maxLimit) =>
442	                dispatch({ type: 'setMaxDiskLimit', value: maxLimit })
443	              }
444	              placeholder={t('All')}
445	            />
446	          </Tooltip>
447	        </FormGroup>
448	      </ExpandableSection>
449	    </>
450	  );
451	};
452	
453	type LocalVolumeSetBodyProps = {
454	  state: State;
455	  dispatch: React.Dispatch<Action>;
456	  storageClassName: string;
457	};

