  1	import * as React from 'react';
  2	import TimesIcon from '@patternfly/react-icons/dist/esm/icons/times-icon';
  3	import {
  4	  Select,
  5	  SelectOption,
  6	  SelectList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  TextInputGroup,
 10	  TextInputGroupMain,
 11	  TextInputGroupUtilities,
 12	  Button,
 13	  SelectProps,
 14	  MenuToggleStatus,
